// Uunimaentie 1, Vantaa — 1970s rivitalo (row house), 4 units
// Long rectangular footprint ~28x8m, 2 stories, brick facade, tile roof

// Foundation
const foundation = translate(box(28, 0.35, 8), 0, 0.175, 0);
scene.add(foundation, {material: "concrete", color: [0.55, 0.55, 0.52]});

// Ground floor walls
const gf_front = translate(box(28, 2.7, 0.25), 0, 1.7, -3.875);
scene.add(gf_front, {material: "concrete", color: [0.65, 0.35, 0.28]});

const gf_back = translate(box(28, 2.7, 0.25), 0, 1.7, 3.875);
scene.add(gf_back, {material: "concrete", color: [0.60, 0.32, 0.25]});

const gf_left = translate(box(0.25, 2.7, 8), -13.875, 1.7, 0);
scene.add(gf_left, {material: "concrete", color: [0.62, 0.33, 0.26]});

const gf_right = translate(box(0.25, 2.7, 8), 13.875, 1.7, 0);
scene.add(gf_right, {material: "concrete", color: [0.62, 0.33, 0.26]});

// Unit dividing walls
const div1 = translate(box(0.2, 2.7, 8), -7, 1.7, 0);
scene.add(div1, {material: "concrete", color: [0.58, 0.30, 0.24]});

const div2 = translate(box(0.2, 2.7, 8), 0, 1.7, 0);
scene.add(div2, {material: "concrete", color: [0.58, 0.30, 0.24]});

const div3 = translate(box(0.2, 2.7, 8), 7, 1.7, 0);
scene.add(div3, {material: "concrete", color: [0.58, 0.30, 0.24]});

// First floor slab
const floor1 = translate(box(28, 0.25, 8), 0, 3.175, 0);
scene.add(floor1, {material: "concrete", color: [0.60, 0.60, 0.58]});

// Upper floor walls
const uf_front = translate(box(28, 2.7, 0.25), 0, 4.65, -3.875);
scene.add(uf_front, {material: "concrete", color: [0.65, 0.35, 0.28]});

const uf_back = translate(box(28, 2.7, 0.25), 0, 4.65, 3.875);
scene.add(uf_back, {material: "concrete", color: [0.60, 0.32, 0.25]});

const uf_left = translate(box(0.25, 2.7, 8), -13.875, 4.65, 0);
scene.add(uf_left, {material: "concrete", color: [0.62, 0.33, 0.26]});

const uf_right = translate(box(0.25, 2.7, 8), 13.875, 4.65, 0);
scene.add(uf_right, {material: "concrete", color: [0.62, 0.33, 0.26]});

// Upper dividers
const udiv1 = translate(box(0.2, 2.7, 8), -7, 4.65, 0);
scene.add(udiv1, {material: "concrete", color: [0.58, 0.30, 0.24]});

const udiv2 = translate(box(0.2, 2.7, 8), 0, 4.65, 0);
scene.add(udiv2, {material: "concrete", color: [0.58, 0.30, 0.24]});

const udiv3 = translate(box(0.2, 2.7, 8), 7, 4.65, 0);
scene.add(udiv3, {material: "concrete", color: [0.58, 0.30, 0.24]});

// Gable roof — ~25deg pitch, tile
const roof_left = translate(rotate(box(28.8, 0.1, 5.2), 0.44, 0, 0), 0, 7.4, -2.2);
scene.add(roof_left, {material: "concrete", color: [0.45, 0.22, 0.18]});

const roof_right = translate(rotate(box(28.8, 0.1, 5.2), -0.44, 0, 0), 0, 7.4, 2.2);
scene.add(roof_right, {material: "concrete", color: [0.45, 0.22, 0.18]});
